// Sentiment analysis and keyword extraction
const question = $input.item.json.userQuestion;

// Simple sentiment analysis (recommend using OpenAI/Claude API in production)
const negativeKeywords = ['angry', 'terrible', 'worst', 'refund', 'complaint', 'issue', 'problem', 'frustrated', 'disappointed'];
const urgentKeywords = ['urgent', 'immediately', 'asap', 'emergency', 'critical', 'now'];
const positiveKeywords = ['thank', 'great', 'excellent', 'satisfied', 'happy', 'appreciate'];

let sentiment = 'neutral';
let urgency = 'normal';
let emotionScore = 0;

// Sentiment scoring
negativeKeywords.forEach(keyword => {
  if (question.toLowerCase().includes(keyword)) {
    emotionScore -= 1;
    sentiment = 'negative';
  }
});

positiveKeywords.forEach(keyword => {
  if (question.toLowerCase().includes(keyword)) {
    emotionScore += 1;
    sentiment = 'positive';
  }
});

urgentKeywords.forEach(keyword => {
  if (question.toLowerCase().includes(keyword)) {
    urgency = 'high';
  }
});

// Very negative cases
if (emotionScore <= -2) {
  sentiment = 'very_negative';
  urgency = 'high';
}

// Keyword extraction (simplified)
const keywords = question
  .replace(/[!?.,]/g, ' ')
  .split(' ')
  .filter(word => word.length > 2)
  .slice(0, 5);

// Language detection (simplified - supports Japanese/English)
const hasKanji = /[\u4e00-\u9faf]/.test(question);
const hasHiragana = /[\u3040-\u309f]/.test(question);
const detectedLanguage = (hasKanji || hasHiragana) ? 'ja' : 'en';

return {
  json: {
    questionId: $input.item.json.questionId,
    userQuestion: question,
    userEmail: $input.item.json.userEmail,
    userName: $input.item.json.userName,
    conversationId: $input.item.json.conversationId,
    timestamp: $input.item.json.timestamp,
    sentiment: sentiment,
    emotionScore: emotionScore,
    urgency: urgency,
    keywords: keywords.join(', '),
    detectedLanguage: detectedLanguage,
    requiresImmediateAttention: sentiment === 'very_negative' || urgency === 'high'
  }
};

