// Knowledge base search simulation
// In production: use Pinecone/Supabase/Qdrant for vector search
const question = $input.item.json.userQuestion;
const language = $input.item.json.detectedLanguage;

// Mock search results (replace with actual vector search)
const mockSearchResults = language === 'ja' ? [
  {
    text: "パスワードリセットは、ログイン画面の「パスワードを忘れた方」リンクから行えます。登録済みのメールアドレスにリセット用のリンクが送信されます。",
    score: 0.85,
    metadata: { category: "Account Management", source: "FAQ-001" }
  },
  {
    text: "メールアドレスの変更は、アカウント設定ページから可能です。セキュリティのため、現在のパスワードの入力が必要になります。",
    score: 0.72,
    metadata: { category: "Account Management", source: "FAQ-003" }
  }
] : [
  {
    text: "To reset your password, click the 'Forgot Password' link on the login page. A reset link will be sent to your registered email address.",
    score: 0.85,
    metadata: { category: "Account Management", source: "FAQ-001" }
  },
  {
    text: "You can change your email address from the Account Settings page. For security reasons, you'll need to enter your current password.",
    score: 0.72,
    metadata: { category: "Account Management", source: "FAQ-003" }
  }
];

return {
  json: {
    ...($input.item.json),
    searchResults: mockSearchResults
  }
};

// Builds AI context from search results and conversation history
const searchResults = $input.item.json.searchResults || [];
const conversationHistory = $('Fetch Conversation History').all();
const currentData = $input.item.json;

// Format conversation history
let historyContext = '';
if (conversationHistory.length > 0) {
  historyContext = '\n【Past Conversation History】\n';
  conversationHistory.forEach((conv, idx) => {
    if (conv.json.conversation_history) {
      historyContext += `${idx + 1}. ${conv.json.conversation_history}\n`;
    }
  });
}

// Format search results
let knowledgeContext = '';
if (Array.isArray(searchResults) && searchResults.length > 0) {
  knowledgeContext = '\n【Knowledge Base Results】\n';
  searchResults.forEach((result, idx) => {
    knowledgeContext += `${idx + 1}. ${result.text}\n`;
    knowledgeContext += `   Relevance: ${(result.score * 100).toFixed(1)}%\n`;
    knowledgeContext += `   Source: ${result.metadata?.source || 'Unknown'}\n\n`;
  });
} else {
  knowledgeContext = '\n【Knowledge Base Results】\nNo relevant information found.\n';
}

// Tone guidance based on sentiment
let toneGuidance = '';
switch(currentData.sentiment) {
  case 'very_negative':
    toneGuidance = 'Use a very polite and apologetic tone. Acknowledge the customer\'s frustration and provide quick solutions.';
    break;
  case 'negative':
    toneGuidance = 'Be empathetic and understanding. Show genuine concern and work towards resolution.';
    break;
  case 'positive':
    toneGuidance = 'Express appreciation and maintain a friendly tone. Keep the positive momentum.';
    break;
  default:
    toneGuidance = 'Use a professional and helpful tone. Provide clear and concise information.';
}

// Build AI prompt
const aiPrompt = `
You are a professional customer support representative. Answer the customer's question based on the following information.

【Customer Information】
Name: ${currentData.userName}
Email: ${currentData.userEmail}
Language: ${currentData.detectedLanguage === 'ja' ? 'Japanese' : 'English'}
Sentiment: ${currentData.sentiment}
Urgency: ${currentData.urgency}

【Question】
${currentData.userQuestion}

${knowledgeContext}
${historyContext}

【Response Guidelines】
${toneGuidance}

【Instructions】
1. Use knowledge base information to provide accurate answers
2. Consider past conversation history if available
3. Include the following metadata at the end:
   CONFIDENCE_SCORE: [0-100]
   REQUIRES_FOLLOWUP: [true/false]
   SUGGESTED_CATEGORY: [category name]
`;

return {
  json: {
    ...currentData,
    knowledgeContext: knowledgeContext,
    historyContext: historyContext,
    toneGuidance: toneGuidance,
    aiPrompt: aiPrompt,
    hasHistory: conversationHistory.length > 0,
    searchResultCount: searchResults.length
  }
};

// AI response generation simulation
// In production: replace with OpenAI/Claude API
const context = $input.item.json;
const language = context.detectedLanguage;

// Generate mock response
const greeting = language === 'ja' ? 
  `${context.userName}様\n\nお問い合わせいただきありがとうございます。` :
  `Dear ${context.userName},\n\nThank you for your inquiry.`;

const mainContent = language === 'ja' ?
  `\n\nご質問の件について、以下の通りご案内させていただきます。\n\n${context.knowledgeContext}\n\n上記の情報がお役に立てば幸いです。` :
  `\n\nRegarding your question, here is the information you need:\n\n${context.knowledgeContext}\n\nI hope this information is helpful.`;

const closing = language === 'ja' ?
  `\n\nご不明な点がございましたら、お気軽にお問い合わせください。\n\n今後ともよろしくお願いいたします。` :
  `\n\nIf you have any further questions, please don't hesitate to ask.\n\nBest regards,\nSupport Team`;

// Calculate confidence score based on search quality
const avgScore = context.searchResults && context.searchResults.length > 0 ?
  context.searchResults.reduce((sum, r) => sum + r.score, 0) / context.searchResults.length :
  0.3;

const confidenceScore = Math.round(avgScore * 100);

// Determine if followup is needed
const requiresFollowup = 
  confidenceScore < 70 || 
  context.sentiment === 'very_negative' ||
  context.searchResultCount === 0;

// Categorize question
const question = context.userQuestion.toLowerCase();
let category = 'General';
if (question.includes('password') || question.includes('パスワード')) category = 'Account Management';
else if (question.includes('payment') || question.includes('支払') || question.includes('billing')) category = 'Billing';
else if (question.includes('bug') || question.includes('error') || question.includes('バグ') || question.includes('エラー')) category = 'Technical Support';
else if (question.includes('refund') || question.includes('返金') || question.includes('cancel')) category = 'Refunds';

const mockAIResponse = `${greeting}${mainContent}${closing}

CONFIDENCE_SCORE: ${confidenceScore}
REQUIRES_FOLLOWUP: ${requiresFollowup}
SUGGESTED_CATEGORY: ${category}`;

return {
  json: {
    ...context,
    response: mockAIResponse
  }
};

// Analyzes AI response and determines routing
const aiResponse = $input.item.json.response;
const contextData = $input.item.json;

// Extract metadata
const confidenceMatch = aiResponse.match(/CONFIDENCE_SCORE:\s*(\d+)/);
const followupMatch = aiResponse.match(/REQUIRES_FOLLOWUP:\s*(true|false)/);
const categoryMatch = aiResponse.match(/SUGGESTED_CATEGORY:\s*(.+)/);

const confidenceScore = confidenceMatch ? parseInt(confidenceMatch[1]) : 0;
const requiresFollowup = followupMatch ? followupMatch[1] === 'true' : false;
const suggestedCategory = categoryMatch ? categoryMatch[1].trim() : 'Uncategorized';

// Clean response (remove metadata)
const cleanResponse = aiResponse
  .replace(/CONFIDENCE_SCORE:\s*\d+/g, '')
  .replace(/REQUIRES_FOLLOWUP:\s*(true|false)/g, '')
  .replace(/SUGGESTED_CATEGORY:\s*.+/g, '')
  .trim();

// Escalation logic
const needsEscalation = 
  confidenceScore < 70 ||  // Low confidence
  requiresFollowup ||       // Needs followup
  contextData.sentiment === 'very_negative' ||  // Very negative
  contextData.urgency === 'high' ||  // High urgency
  cleanResponse.includes('escalate') || // Explicit escalation
  contextData.searchResultCount === 0;  // No knowledge base results

// Priority scoring
let priorityScore = 0;
if (contextData.sentiment === 'very_negative') priorityScore += 30;
if (contextData.urgency === 'high') priorityScore += 25;
if (confidenceScore < 50) priorityScore += 20;
if (requiresFollowup) priorityScore += 15;
if (contextData.emotionScore < -1) priorityScore += 10;
if (contextData.searchResultCount === 0) priorityScore += 10;

const priority = priorityScore >= 50 ? 'critical' : 
                 priorityScore >= 30 ? 'high' : 
                 priorityScore >= 15 ? 'medium' : 'low';

// Estimated response time
const estimatedResponseTime = 
  priority === 'critical' ? 'Within 1 hour' :
  priority === 'high' ? 'Within 4 hours' :
  priority === 'medium' ? 'Within 24 hours' : 'Within 48 hours';

return {
  json: {
    questionId: contextData.questionId,
    conversationId: contextData.conversationId,
    userQuestion: contextData.userQuestion,
    userEmail: contextData.userEmail,
    userName: contextData.userName,
    aiResponse: cleanResponse,
    confidenceScore: confidenceScore,
    requiresFollowup: requiresFollowup,
    suggestedCategory: suggestedCategory,
    needsEscalation: needsEscalation,
    priority: priority,
    priorityScore: priorityScore,
    sentiment: contextData.sentiment,
    emotionScore: contextData.emotionScore,
    urgency: contextData.urgency,
    detectedLanguage: contextData.detectedLanguage,
    keywords: contextData.keywords,
    status: needsEscalation ? 'escalated' : 'auto_resolved',
    timestamp: contextData.timestamp,
    hasHistory: contextData.hasHistory,
    searchResultCount: contextData.searchResultCount,
    estimatedResponseTime: estimatedResponseTime
  }
};

